mapper.select:
SELECT fm.id, fm.name, fm.gender, fm.birth_date as birthDate, fm.birth_place as birthPlace, fm.death_date as deathDate, fm.bio, fm.avatar, fm.family_id as genealogyId, f.name as genealogyName, fm.user_id as userId, ug.role as accountRole, fm.create_time as createdAt FROM family_member fm LEFT JOIN family f ON fm.family_id = f.id LEFT JOIN user_genealogy ug ON fm.user_id = ug.user_id AND fm.family_id = ug.genealogy_id
AND fm.name LIKE CONCAT('%', #{query.name}, '%')
AND fm.gender = #{query.gender}
AND fm.birth_date >= #{query.birthDateStart}
AND fm.birth_date <= #{query.birthDateEnd}
AND fm.family_id = #{query.genealogyId}
AND fm.create_time >= #{query.createTimeStart}
AND fm.create_time <= #{query.createTimeEnd}
ORDER BY fm.create_time DESC
